  ('judicial-57112235-moex-00001', 'judicial-57112235', 'judicial-57112235-moex-114-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '下列何項原則不屬於罪刑法定原則之內涵？', '["禁止類推適用原則", "罪刑明確性原則", "不利益變更禁止原則", "禁止溯及既往原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00002', 'judicial-57112235', 'judicial-57112235-moex-114-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '有關法律變更的敘述，下列何者正確？', '["依刑法第2條第1項本文之規定，行為後法律有變更時，原則上適用裁判時之法律", "刑法第2條第1項所稱之法律，僅限於涉及犯罪成立之要件，而不含刑罰效果", "依刑法第2條第2項之規定，沒收與所有的保安處分均適用裁判時之法律", "刑罰之內容於行為後有變更者，結論上應適用最有利於行為人之法律"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00003', 'judicial-57112235', 'judicial-57112235-moex-114-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '依刑法規定、實務及通說見解，下列何者之情形不該當刑法上之重傷概念？', '["甲將乙右手大拇指、食指及中指砍斷，僅留無名指與小指", "甲用球棒毆打乙，使乙之膝關節無法伸直", "甲用球棒毆打乙，使乙昏迷成為植物人", "甲用球棒毆打乙，使乙腳骨折經一年復健始能正常行走"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00004', 'judicial-57112235', 'judicial-57112235-moex-114-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲為A上市公司執行長，某日酒駕肇事，乃與坐在副手座的乙交換，並提供新臺幣300萬元安家費，要乙 承認自己為駕駛人。依實務見解，下列何者正確？', '["甲成立刑法第164條第2項意圖隱避犯人頂替罪之教唆犯", "乙成立刑法第164條第2項意圖隱避犯人頂替罪之幫助犯", "甲成立刑法第164條第2項的意圖隱避犯人頂替罪", "乙成立刑法第164條第2項的意圖隱避犯人頂替罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00005', 'judicial-57112235', 'judicial-57112235-moex-114-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '有關罪刑法定原則，下列敘述何者錯誤？', '["其目的在防止國家濫用刑罰，並藉此保障人民權利", "國家必須事先以成文法律明確規定犯罪要件與制裁內容", "習慣法不得作為成立犯罪之依據", "保安處分一律適用裁判時之法律"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
